/**
 * Structured comparison pairs auto-generated by `scripts/generate-comparison-pages.ts`.
 * Each entry encodes which sites are paired, the niche overlap that drove the
 * pairing, and a suggested winner / runner-up so ComparePage can render a
 * deterministic verdict without recomputing on every render.
 *
 * Regenerate with:
 *   npx tsx scripts/generate-comparison-pages.ts
 */

export interface ComparisonPair {
  /** URL slug fragment: `${a}-vs-${b}` (sorted alphabetically for canonicalisation) */
  slug: string;
  siteA: string;
  siteB: string;
  /** Niche shared by both sites — drives the pairing and the niche-internal-link block */
  primaryNiche: string | null;
  /** Slug of the suggested overall winner (higher score) */
  suggestedWinner: string;
  /** Slug of the runner-up (cheaper of the two on annual) */
  suggestedRunnerUp: string;
  /** Search-volume priority hint, 1 (low) – 5 (top); pairs with priority >= 4 are surfaced as "Popular Comparisons" */
  priority: number;
}

