export const getComparisonPair = (slug: string): ComparisonPair | undefined =>
  comparisonPairs.find((p) => p.slug === slug);

export const getComparisonsByNiche = (nicheSlug: string): ComparisonPair[] =>
  comparisonPairs.filter((p) => p.primaryNiche === nicheSlug);

export const getPopularComparisons = (count: number = 6): ComparisonPair[] =>
  [...comparisonPairs]
    .sort((a, b) => b.priority - a.priority)
    .slice(0, count);
